     9→import { createModel, createType } from '../schema';
    10→
    11→import { Cache } from './cache';
    12→import {
    13→  type AsyncSliceState,
    14→  type CacheStrategy,
    15→  type CreateAsyncSlice,
    16→  type CreateSlice,
    17→  type MachineAction,
    18→  type MachineReducer,
    19→  type MachineSliceInfo,
    20→  type MachineSlices,
    21→  type MachineState,
    22→  type RuntimeActionCreator,
    23→  type SliceContext,
    24→  SliceKind,
    25→  type SliceReducer,
    26→  type StringTypes,
    27→} from './models';
    28→
    29→export namespace Slices {
    30→  export type SliceMapReducer = MachineReducer & { info: MachineSliceInfo };
    31→  // prettier-ignore
    32→  export type SliceMap = {
    33→    reducer: SliceMapReducer;
    34→    actionCreatorByType: { [K in StringTypes.ActionType]: RuntimeActionCreator };
    35→    actionCreatorListBySliceKey: { [K in StringTypes.SliceKey]: RuntimeActionCreator[] };
    36→    actionCreatorsSliceKey: { [K in StringTypes.SliceKey]: { [K: string]: RuntimeActionCreator } };
    37→    actionTypesBySliceKey: { [K in StringTypes.SliceKey]: { [K: string]: string } };
    38→    reducerBySliceKey: { [K: StringTypes.SliceKey]: SliceMapReducer };
    39→    reducerByActionType: { [K in StringTypes.ActionType]: SliceMapReducer };
    40→    actionTypeList: StringTypes.ActionType[];
    41→  };
    42→
    43→  /** Explicit type for sync slice model */
    44→  export type SyncSliceModel = {
    45→    id: string;
    46→    kind: SliceKind.sync;
    47→    initial: unknown;
    48→    reducers: Record<string, SliceReducer>;
    49→    cache: CacheStrategy;
    50→  };
    51→
    52→  /** Explicit type for async slice model */
    53→  export type AsyncSliceModel = {
    54→    id: string;
    55→    kind: SliceKind.async;
    56→    initial: AsyncSliceState<unknown>;
    57→    load: (...args: any[]) => Promise<unknown>;
    58→    context: SliceContext;
    59→    cache: CacheStrategy;
    60→  };
    61→
    62→  export type SlicesMap = Omit<SliceMap, 'reducer'> & {
    63→    info: MachineSliceInfo[];
    64→    mergedSlicesInitialContext: SliceContext;
    65→    mergedSlicesInitialState: AnyRecord;
    66→  };
    67→
    68→  export const SyncSliceModel = createModel({
    69→    id: 'string',
    70→    kind: { enum: [SliceKind.sync] },
    71→    initial: 'unknown',
    72→    reducers: { record: 'function' },
    73→    cache: Cache.Model,
    74→  });
    75→
    76→  export const AsyncSliceModel = createModel({
    77→    id: 'string',
    78→    kind: { enum: [SliceKind.async] },
    79→    initial: 'any',
    80→    load: 'function',
    81→    context: 'object',
    82→    cache: Cache.Model,
    83→  });
    84→
    85→  export const AnySliceModel = createType({
    86→    union: [SyncSliceModel, AsyncSliceModel],
    87→  });
    88→
    89→  export function IsSyncSliceKind(value: unknown): value is SyncSliceModel {
    90→    assertObject(value);
    91→    return SyncSliceModel.isValid(value);
    92→  }
    93→
    94→  export function IsAsyncSliceKind(value: unknown): value is AsyncSliceModel {
    95→    assertObject(value);
    96→    return AsyncSliceModel.isValid(value);
    97→  }
    98→
    99→  export const AsyncReducerNames = new Set(['load', 'success', 'fail', 'clear'] as const);
   100→
   101→  /**
   102→   * Maps one slice to internal machine utils
   103→   * @param machineID
   104→   * @param map
   105→   * @constructor
   106→   */
   107→  export function MapSlice(machineID: string, map: MachineSliceInfo): SliceMap {
   108→    const { sliceKey, slice, actionPrefix } = map;
   109→    let reducer = null as SliceMapReducer | null;
   110→    const actionCreatorByType = {} as SlicesMap['actionCreatorByType'];
   111→    const reducerByActionType = {} as SlicesMap['reducerByActionType'];
   112→    // prettier-ignore
   113→    const actionCreatorListBySliceKey = {} as SlicesMap['actionCreatorListBySliceKey'];
   114→    const actionCreatorsSliceKey = {} as SlicesMap['actionCreatorsSliceKey'];
   115→    const actionTypesBySliceKey = {} as SlicesMap['actionTypesBySliceKey'];
   116→    const actionTypeList = [] as SlicesMap['actionTypeList'];
   117→
   118→    const namePrefix = `${machineID}${capitalize(sliceKey)}`;
   119→
   120→    function registerAction(reducerName: StringTypes.SliceReducerName): RuntimeActionCreator {
   121→      const actionType = `${actionPrefix}${reducerName}` as StringTypes.ActionType;
   122→
   123→      function action(payload: unknown): MachineAction {
   124→        return {
   125→          type: actionType,
   126→          payload,
   127→        };
   128→      }
   129→
   130→      defineFunctionName(action, `${namePrefix}${capitalize(reducerName)}RuntimeActionCreator`);
   131→      action.info = map;
   132→      action.type = actionType;
   133→      action.sliceReducerName = reducerName;
   134→      actionCreatorByType[actionType] = action;
   135→      actionTypeList.push(actionType);
   136→      // prettier-ignore
   137→      actionCreatorListBySliceKey[sliceKey] = actionCreatorListBySliceKey[sliceKey] || [];
   138→      actionCreatorsSliceKey[sliceKey] = actionCreatorsSliceKey[sliceKey] || {};
   139→      actionTypesBySliceKey[sliceKey] = actionTypesBySliceKey[sliceKey] || {};
   140→      actionTypesBySliceKey[sliceKey][reducerName] = actionType;
   141→      actionCreatorListBySliceKey[sliceKey].push(action);
   142→      actionCreatorsSliceKey[sliceKey][reducerName] = action;
   143→      return action;
   144→    }
   145→
   146→    if (IsAsyncSliceKind(slice)) {
   147→      AsyncReducerNames.forEach((name) => {
   148→        return registerAction(name as StringTypes.SliceReducerName);
   149→      });
   150→
   151→      const fn = function reducer(state = slice.initial as MachineState, action: MachineAction) {
   152→        // prettier-ignore
   153→        const localAction = actionCreatorByType[action.type as StringTypes.ActionType];
   154→        if (!localAction) return state;
   155→
   156→        const sliceReducerName = localAction.sliceReducerName;
   157→
   158→        return produce(state, (draft) => {
   159→          switch (sliceReducerName) {
   160→            case 'load': {
   161→              draft.loading = true;
   162→              draft.failed = false;
   163→              draft.error = null;
   164→              return;
   165→            }
   166→            case 'success': {
   167→              draft.loading = false;
   168→              draft.loaded = true;
   169→              draft.value = action.payload;
   170→              return;
   171→            }
   172→            case 'fail': {
   173→              const error = getProperty(action.payload, 'error', true);
   174→              draft.loading = false;
   175→              draft.failed = true;
   176→              draft.error = error as string;
   177→              return;
   178→            }
   179→            case 'clear': {
   180→              return slice.initial;
   181→            }
   182→            default: {
   183→              return;
   184→            }
   185→          }
   186→        });
   187→      };
   188→      fn.info = map;
   189→      reducer = fn;
   190→    } else if (IsSyncSliceKind(slice)) {
   191→      const syncSlice = slice as SyncSliceModel;
   192→      const sliceReducersByActionTypes = new Map<string, SliceReducer>();
   193→
