     2→ * TypeBox abstraction layer.
     3→ * This is the ONLY file that should import from 'typebox' directly.
     4→ */
     5→
     6→import { type Static, type TSchema, Type } from 'typebox';
     7→import { Compile } from 'typebox/compile';
     8→import { Value } from 'typebox/value';
     9→
    10→/** Custom kind identifier for Date type (TypeBox 1.x uses ~kind property) */
    11→const CUSTOM_DATE_KIND = 'CustomDate';
    12→
    13→/**
    14→ * Cache for compiled validators.
    15→ * WeakMap allows garbage collection of unused schemas.
    16→ */
    17→const compiledValidatorCache = new WeakMap<TSchema, ReturnType<typeof Compile>>();
    18→
    19→/**
    20→ * Get or create a compiled validator for a schema.
    21→ * Compiled validators are 10-100x faster than Value.Check interpreter.
    22→ */
    23→function getCompiledValidator(schema: TSchema): ReturnType<typeof Compile> {
    24→  let validator = compiledValidatorCache.get(schema);
    25→  if (!validator) {
    26→    validator = Compile(schema);
    27→    compiledValidatorCache.set(schema, validator);
    28→  }
    29→  return validator;
    30→}
    31→
    32→/**
    33→ * Check if a schema is our custom Date type.
    34→ */
    35→function isCustomDateSchema(schema: TSchema): boolean {
    36→  return (schema as any)['~customKind'] === CUSTOM_DATE_KIND;
    37→}
    38→
    39→/**
    40→ * Validate a value as a Date object.
    41→ */
    42→function isValidDate(value: unknown): value is Date {
    43→  return value instanceof Date && !isNaN(value.getTime());
    44→}
    45→
    46→/**
    47→ * Creates a TypeBox schema for validating Date objects.
    48→ */
    49→export function createDateType(): TSchema {
    50→  return Type.Unsafe<Date>({ '~customKind': CUSTOM_DATE_KIND });
    51→}
    52→
    53→/**
    54→ * Infers the TypeScript type from a TypeBox schema.
    55→ */
    56→export type TypeBoxInfer<T extends TSchema> = Static<T>;
    57→
    58→/**
    59→ * Result of createBaseType - contains the schema and validation utilities.
    60→ */
