import React from 'react';

import { getProperty } from '../helpers/object-utils';

import type { SliceContext, StringTypes, UnknownAction } from './models';
import type { Slices } from './slice';
import type { Store } from './store';

export function Hooks(params: {
  machineID: string;
  store: Store.Instance;
  getContext(): SliceContext;
  mappedSlices: Slices.SlicesMap;
}) {
  const { store, getContext, mappedSlices } = params;

  function useSelector<T>(selector: (state: any) => T): T {
    return React.useSyncExternalStore(store.subscribe, () => {
      const fullState = store.getState();
      return selector(fullState);
    });
  }

  // transforming action creators into action dispatchers
  const runtimeActions = {} as {
    [K: StringTypes.SliceKey]: {
      [K: StringTypes.SliceReducerName]: (payload: unknown) => UnknownAction;
    };
  };

  mappedSlices.info.forEach(({ sliceKey }) => {
    const actions = mappedSlices.actionCreatorListBySliceKey[sliceKey];
    if (!actions) return;
    actions.forEach((actionCreator) => {
      runtimeActions[sliceKey] = runtimeActions[sliceKey] || {};
      runtimeActions[sliceKey][actionCreator.sliceReducerName] = (payload: unknown) => {
        const context = getContext();
        const actionObject = actionCreator(payload, context);
        return store.dispatch(actionObject);
      };
    });
  });

  /**
   * Custom React hook to interact with a specific slice of the state machine.
   * Returns plain object { state, actions }.
   *
   * @param path The key of the slice or selector to access.
   * @returns The slice's state and associated actions
   */
  function useMachine(path: string) {
    const isSliceKey = Boolean(mappedSlices.reducerBySliceKey[path as StringTypes.SliceKey]);

    const actionsRef = React.useRef(
      isSliceKey ? runtimeActions[path as StringTypes.SliceKey] : undefined,
    );

    const stateRef = React.useRef<unknown>(null);

    return useSelector((state) => {
      const selection = getProperty(state, path, true);
      if (selection !== stateRef.current) {
        stateRef.current = selection;
      }

      return isSliceKey
        ? {
            state: stateRef.current,
            actions: actionsRef.current,
          }
        : stateRef.current;
    });
  }

  return {
    useSelector,
    useMachine,
  };
}

